// ─── FAZ 7 — HAFTALIK ÖZET + YILLIK İSTATİSTİK ───────────────────────────────
function haftalikOzetH(){
var bugun=new Date();var gunler=[];
for(var i=0;i<7;i++){var d=new Date(bugun);d.setDate(bugun.getDate()-bugun.getDay()+1+i);gunler.push(d.toISOString().slice(0,10));}
var menuPlanlanan=gunler.filter(function(g){var m=S.M[g]||{};return m.a||m.k||m.sp;}).length;
var simdi=new Date();var ay=simdi.getMonth();var yil=simdi.getFullYear();
var aylikHarcama=0;if(S.GIDER){aylikHarcama=S.GIDER.filter(function(g){var d=new Date(g.dt);return d.getMonth()===ay&&d.getFullYear()===yil;}).reduce(function(s,g){return s+g.amt;},0);}
var bekleyenSosyal=0;if(S.SOSYAL&&S.SOSYAL.aktiviteler){bekleyenSosyal=S.SOSYAL.aktiviteler.filter(function(a){return!a.tamamlandi;}).length;}
var menuPct=Math.round((menuPlanlanan/7)*100);
return '<div class="cd" style="background:linear-gradient(135deg,var(--primary),#7D3C98);color:#fff;margin-bottom:12px;cursor:pointer" onclick="go(\'yillik\')">'+
'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px">'+
'<span style="font-family:Fraunces,serif;font-size:14px;font-weight:800">Bu Hafta</span>'+
'<span style="font-size:10px;opacity:.7">Özet için dokun →</span></div>'+
'<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px">'+
'<div style="background:rgba(255,255,255,.15);border-radius:10px;padding:10px;text-align:center">'+
'<div style="font-size:26px;font-weight:900">'+menuPlanlanan+'/7</div>'+
'<div style="width:100%;height:4px;background:rgba(255,255,255,.25);border-radius:2px;margin:5px 0 4px"><div style="width:'+menuPct+'%;height:100%;background:#fff;border-radius:2px"></div></div>'+
'<div style="font-size:9px;opacity:.8">Ηaftalık Menü</div></div>'+
'<div style="background:rgba(255,255,255,.15);border-radius:10px;padding:10px;text-align:center">'+
'<div style="font-size:26px;font-weight:900">'+bekleyenSosyal+'</div>'+
'<div style="font-size:9px;opacity:.8;margin-top:9px">Bekleyen Aktivite</div></div>'+
'<div style="background:rgba(255,255,255,.15);border-radius:10px;padding:10px;text-align:center">'+
'<div style="font-size:16px;font-weight:900;margin-top:2px">'+fmt(aylikHarcama)+'</div>'+
'<div style="font-size:9px;opacity:.8;margin-top:5px">Aylık Harcama</div></div>'+
'</div></div>';}

function yillikH(){
var yil=new Date().getFullYear();
var yillikHarcama=0;var katHarcama={};
if(S.GIDER){S.GIDER.filter(function(g){return new Date(g.dt).getFullYear()===yil;}).forEach(function(g){yillikHarcama+=g.amt;katHarcama[g.cat]=(katHarcama[g.cat]||0)+g.amt;});}
var topKatlar=Object.entries(katHarcama).sort(function(a,b){return b[1]-a[1];}).slice(0,5);
var aylikH=Array(12).fill(0);
if(S.GIDER){S.GIDER.filter(function(g){return new Date(g.dt).getFullYear()===yil;}).forEach(function(g){aylikH[new Date(g.dt).getMonth()]+=g.amt;});}
var maxAy=Math.max.apply(null,aylikH)||1;
var ay=['Oca','\u015eub','Mar','Nis','May','Haz','Tem','\u0130\u00f6n','Eyl','Eki','Kas','Ara'];
var aktiviteSayisi=0;var puanOrt=0;
if(S.SOSYAL&&S.SOSYAL.aktiviteler){var tamam=S.SOSYAL.aktiviteler.filter(function(a){return a.tamamlandi;});aktiviteSayisi=tamam.length;if(tamam.length>0)puanOrt=Math.round(tamam.reduce(function(s,a){return s+((a.puan_gorkem||0)+(a.puan_esra||0))/2;},0)/tamam.length);}
hedefInitCheck();var tamamH=S.HEDEF.liste.filter(function(h){return h.tamamlandi;}).length;var devamH=S.HEDEF.liste.filter(function(h){return!h.tamamlandi;}).length;
var bakimSayisi=0;if(S.C&&S.C.hs)bakimSayisi=S.C.hs.filter(function(h){return new Date(h.dt).getFullYear()===yil;}).length;
var vetSayisi=0;if(S.PET&&S.PET.vi){var tum=[].concat(S.PET.vi.waffle||[],S.PET.vi.mayis||[]);vetSayisi=tum.filter(function(v){return new Date(v.dt).getFullYear()===yil;}).length;}
var kasaToplam=0;if(S.KASA)kasaToplam=(S.KASA.gorkem||0)+(S.KASA.esra||0)+(S.KASA.ortak||0);
var bars=aylikH.map(function(v,i){var h=Math.round((v/maxAy)*60);return'<div style="display:flex;flex-direction:column;align-items:center;gap:2px;flex:1"><div style="font-size:7px;color:rgba(255,255,255,.7)">'+(v>0?fmt(v).replace(/[₺.]/g,'').slice(0,4):'')+'</div><div style="width:100%;background:rgba(255,255,255,.3);border-radius:2px 2px 0 0;height:'+h+'px;min-height:2px"></div><div style="font-size:8px;color:rgba(255,255,255,.7)">'+ay[i]+'</div></div>';}).join('');
var katRows=topKatlar.map(function(e){var pct=yillikHarcama?Math.round((e[1]/yillikHarcama)*100):0;return'<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;border-bottom:1px solid var(--brd)"><span style="font-size:12px">'+esc(e[0])+'</span><div style="display:flex;align-items:center;gap:8px"><div style="width:60px;height:6px;background:var(--bg);border-radius:3px"><div style="width:'+pct+'%;height:100%;background:var(--primary);border-radius:3px"></div></div><span style="font-size:12px;font-weight:800;width:50px;text-align:right">'+fmt(e[1])+'</span></div></div>';}).join('');
return'<div class="app"><div class="hdr" style="background:var(--primary)"><div style="display:flex;align-items:center;gap:8px"><div style="font-size:14px;color:rgba(255,255,255,.7);cursor:pointer;min-width:44px;min-height:44px;display:flex;align-items:center" onclick="go(\'home\')">&#9664;</div><div><h1>'+yil+' Y\u0131ll\u0131k \u00d6zet</h1></div></div></div>'+
'<div class="cnt fi">'+
'<div class="g2" style="gap:8px;margin-bottom:12px">'+
'<div class="cd" style="text-align:center;padding:12px"><div style="font-size:24px;font-weight:900;color:var(--primary)">'+fmt(yillikHarcama)+'</div><div style="font-size:11px;color:var(--txtL)">Toplam Harcama</div></div>'+
'<div class="cd" style="text-align:center;padding:12px"><div style="font-size:24px;font-weight:900;color:var(--succ)">'+fmt(kasaToplam)+'</div><div style="font-size:11px;color:var(--txtL)">Kasa Toplam\u0131</div></div>'+
'<div class="cd" style="text-align:center;padding:12px"><div style="font-size:24px;font-weight:900;color:var(--acc)">'+aktiviteSayisi+'</div><div style="font-size:11px;color:var(--txtL)">Aktivite</div></div>'+
'<div class="cd" style="text-align:center;padding:12px"><div style="font-size:24px;font-weight:900;color:#E91E63">'+tamamH+'</div><div style="font-size:11px;color:var(--txtL)">Hedef Tamamland\u0131</div></div>'+
'</div>'+
'<div class="cd" style="background:linear-gradient(135deg,var(--primary),#7D3C98);color:#fff"><h3 style="color:#fff;margin-bottom:10px">&#128202; Ayl\u0131k Harcama '+yil+'</h3><div style="display:flex;align-items:flex-end;gap:3px;height:80px;padding-top:12px">'+bars+'</div></div>'+
(topKatlar.length?'<div class="cd"><h3>&#127991;&#65039; En \u00c7ok Harcama</h3>'+katRows+'</div>':'')+
'<div class="cd"><h3>&#127919; Sosyal</h3><div class="g2"><div style="text-align:center"><div style="font-size:28px;font-weight:900;color:var(--primary)">'+aktiviteSayisi+'</div><div style="font-size:11px;color:var(--txtL)">Aktivite</div></div><div style="text-align:center"><div style="font-size:28px;font-weight:900;color:var(--warn)">'+puanOrt+'</div><div style="font-size:11px;color:var(--txtL)">Ort. Puan</div></div></div></div>'+
'<div class="cd"><h3>&#127942; Hedefler</h3><div class="g2"><div style="text-align:center"><div style="font-size:28px;font-weight:900;color:var(--succ)">'+tamamH+'</div><div style="font-size:11px;color:var(--txtL)">Tamamlanan</div></div><div style="text-align:center"><div style="font-size:28px;font-weight:900;color:var(--warn)">'+devamH+'</div><div style="font-size:11px;color:var(--txtL)">Devam Eden</div></div></div></div>'+
'<div class="cd"><h3>&#128663;&#128062; Bak\u0131m</h3><div class="g2"><div style="text-align:center"><div style="font-size:28px;font-weight:900;color:var(--arac)">'+bakimSayisi+'</div><div style="font-size:11px;color:var(--txtL)">Ara\u00e7 Bak\u0131m</div></div><div style="text-align:center"><div style="font-size:28px;font-weight:900;color:var(--acc)">'+vetSayisi+'</div><div style="font-size:11px;color:var(--txtL)">Veteriner</div></div></div></div>'+
'</div></div>';}
