function onlineDot(){const on=typeof fbOn!=='undefined'&&fbOn;return'<span style="width:7px;height:7px;border-radius:50%;flex-shrink:0;display:inline-block;background:'+(on?'#4CD964':'#FF3B30')+';'+(on?'animation:pulse 2s infinite;':'')+'" title="'+(on?'Çevrimiçi':'Çevrimdışı')+'"></span>'}

